const user=JSON.parse(sessionStorage.getItem('dm_user')||'null');if(!Api.token()||!user)location.href='login.html';
const baseLeafletMap=L.map;L.map=function(element,options={}){return baseLeafletMap.call(L,element,{maxBounds:Config.MAP_BOUNDS,maxBoundsViscosity:1,minZoom:9,...options});};
const manager=['admin','subadmin'].includes(user?.role), colors={low:'#10b981',moderate:'#f59e0b',high:'#f97316',critical:'#dc2626'};document.body.dataset.role=user.role;
document.getElementById('reportForm')?.classList.add('hidden');
document.getElementById('userName').textContent=user?.fullname||'';document.getElementById('roleLabel').textContent=user?.role==='subadmin'?'Sub Admin':(user?.role||'');document.getElementById('avatar').textContent=(user?.fullname||'U')[0].toUpperCase();
if(!manager){document.querySelectorAll('.manager-only').forEach(el=>el.remove());document.getElementById('view-reports')?.remove();}
if(user?.role!=='admin')document.querySelectorAll('.admin-only').forEach(el=>el.remove());
if(user?.role==='subadmin')document.querySelector('[data-view="history"]')?.remove();
document.getElementById('logoutBtn').onclick=async()=>{if(!await confirmAction('Sign out of Disaster Map?','You will need to sign in again.','Sign out'))return;showLoading('Signing out…');try{await Api.post('/auth/logout',{});closeLoading();await Swal.fire({icon:'success',title:'Signed out',timer:700,showConfirmButton:false});}finally{sessionStorage.clear();location.href='login.html';}};
document.getElementById('menuBtn').onclick=()=>document.getElementById('sidebar').classList.toggle('hidden');
document.querySelectorAll('.nav-item').forEach(btn=>btn.onclick=()=>{document.querySelectorAll('.crud-modal:not(.hidden)').forEach(modal=>{modal.classList.add('hidden');modal.classList.remove('flex');});document.body.classList.remove('modal-open');document.querySelectorAll('.view').forEach(v=>v.classList.add('hidden'));document.querySelectorAll('.nav-item').forEach(n=>n.classList.remove('nav-active'));const target=document.getElementById(`view-${btn.dataset.view}`);if(!target)return;target.classList.remove('hidden');btn.classList.add('nav-active');if(btn.dataset.view==='weather')loadWeatherModule(false);if(btn.dataset.view==='hazards')setTimeout(initAdminMap,0);if(btn.dataset.view==='safezones')setTimeout(initSafeZoneMap,0);if(btn.dataset.view==='centers')setTimeout(initCenterMap,0);if(btn.dataset.view==='routes')setTimeout(initRouteMap,0);if(btn.dataset.view==='alerts')loadAlertCenter();if(btn.dataset.view==='history')loadHistoricalDisasters();if(btn.dataset.view==='reports')loadReports();if(btn.dataset.view==='users')loadUsers();if(btn.dataset.view==='municipalities')loadMunicipalities();if(btn.dataset.view==='profile')loadProfile();});
function alertMarkup(a){return `<article class="rounded-xl border-l-4 ${a.alert_level==='critical'?'border-red-600':'border-amber-500'} bg-slate-50 p-3"><strong class="text-sm">${escapeText(a.title)}</strong><p class="mt-1 text-xs text-slate-600">${escapeText(a.message)}</p></article>`;}
function escapeText(v){const e=document.createElement('div');e.textContent=v??'';return e.innerHTML;}
const cardMeta={total_residents:['Total Residents','People','indigo'],total_municipalities:['Total Municipalities','Areas','sky'],total_hazards:['Total Hazards','Active','orange'],total_safe_zones:['Total Safe Zones','Available','emerald'],total_evacuation_centers:['Total Evacuation Centers','Available','violet'],total_alerts:['Total Alerts','Published','red'],total_reports:['Total Reports','Generated','sky'],active_alerts:['Active Alerts','Current','red'],nearby_safe_zones:['Nearby Safe Zones','Municipality','emerald'],nearby_evacuation_centers:['Nearby Evacuation Centers','Municipality','violet'],weather_status:['Weather Status','Live','sky']};
const cardColors={indigo:'bg-indigo-50 text-indigo-700',sky:'bg-sky-50 text-sky-700',orange:'bg-orange-50 text-orange-700',emerald:'bg-emerald-50 text-emerald-700',violet:'bg-violet-50 text-violet-700',red:'bg-red-50 text-red-700'};
let dashboardCharts=[];
function renderCards(cards){document.getElementById('stats').innerHTML=Object.entries(cards).map(([key,value])=>{const [label,note,color]=cardMeta[key]||[key,'','indigo'];return `<article data-card="${key}" class="rounded-2xl border bg-white p-5 shadow-sm"><div class="flex items-start justify-between"><div><p class="text-sm text-slate-500">${label}</p><p data-value class="mt-2 text-3xl font-bold text-slate-900">${value??'Loading…'}</p></div><span class="rounded-lg px-2 py-1 text-xs font-semibold ${cardColors[color]}">${note}</span></div></article>`;}).join('');}
function renderCharts(charts){dashboardCharts.forEach(c=>c.destroy());dashboardCharts=[];const make=(id,type,rows,colors)=>{const ctx=document.getElementById(id);dashboardCharts.push(new Chart(ctx,{type,data:{labels:rows.map(x=>x.label),datasets:[{label:'Count',data:rows.map(x=>x.value),backgroundColor:colors,borderColor:type==='line'?'#4f46e5':undefined,borderWidth:type==='line'?3:0,tension:.35,fill:type==='line'}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:type==='doughnut'}},scales:type==='doughnut'?{}:{y:{beginAtZero:true,ticks:{precision:0}},x:{grid:{display:false}}}}}));};make('severityChart','doughnut',charts.hazards_by_severity,['#dc2626','#f97316','#f59e0b','#10b981']);make('alertsChart','line',charts.alerts_last_six_months,'rgba(79,70,229,.15)');make('facilitiesChart','bar',charts.facilities,['#10b981','#8b5cf6']);}
function browserLocation(){return new Promise(resolve=>user.role==='resident'&&navigator.geolocation?navigator.geolocation.getCurrentPosition(p=>resolve({latitude:p.coords.latitude,longitude:p.coords.longitude}),()=>resolve(null),{timeout:5000,maximumAge:300000}):resolve(null));}
function weatherPosition(){return new Promise(resolve=>navigator.geolocation?navigator.geolocation.getCurrentPosition(p=>resolve({latitude:p.coords.latitude,longitude:p.coords.longitude}),()=>resolve(null),{timeout:7000,maximumAge:300000}):resolve(null));}
async function weatherData(position=null){const query=position?`?latitude=${position.latitude}&longitude=${position.longitude}`:'';return Api.get(`/weather/current${query}`);}
async function loadWeather(position){if(user.role!=='resident')return;const value=document.querySelector('[data-card="weather_status"] [data-value]');try{const data=await weatherData(position);value.textContent=`${data.current.condition} · ${Math.round(data.current.temperature_c)}°C`;value.closest('article').title=`Warning level: ${data.warning_level}`;}catch{value.textContent='Unavailable';}}
const weatherLevelClasses={normal:'border-emerald-200 bg-emerald-50 text-emerald-900',advisory:'border-sky-200 bg-sky-50 text-sky-900',warning:'border-amber-200 bg-amber-50 text-amber-900',critical:'border-red-200 bg-red-50 text-red-900'};
async function loadWeatherModule(useBrowserLocation=false){const condition=document.getElementById('weatherCondition');condition.textContent='Loading…';try{const position=useBrowserLocation?await weatherPosition():null,data=await weatherData(position),c=data.current;document.getElementById('weatherLocation').textContent=`${data.location.name} · ${data.location.latitude.toFixed(4)}, ${data.location.longitude.toFixed(4)}`;condition.textContent=c.condition;document.getElementById('weatherTemperature').textContent=`${Math.round(c.temperature_c)}°C · Feels like ${Math.round(c.apparent_temperature_c)}°C`;const warning=document.getElementById('weatherWarningLevel');warning.textContent=data.warning_level.toUpperCase();warning.className=`mt-2 text-2xl font-bold ${data.warning_level==='critical'?'text-red-600':data.warning_level==='warning'?'text-amber-600':data.warning_level==='advisory'?'text-sky-600':'text-emerald-600'}`;document.getElementById('weatherHumidity').textContent=`${c.humidity_percent}%`;document.getElementById('weatherClouds').textContent=`Cloud cover ${c.cloud_cover_percent}% · Pressure ${Math.round(c.pressure_hpa)} hPa`;document.getElementById('weatherWind').textContent=`${Math.round(c.wind_speed_kmh)} km/h`;document.getElementById('weatherGust').textContent=`Gusts up to ${Math.round(c.wind_gust_kmh)} km/h`;document.getElementById('weatherAdvisories').innerHTML=Object.values(data.advisories).map(a=>`<article class="rounded-2xl border p-5 ${weatherLevelClasses[a.level]}"><div class="flex items-center justify-between gap-2"><h2 class="font-semibold">${escapeText(a.title)}</h2><span class="rounded-full bg-white/70 px-2 py-1 text-xs font-bold uppercase">${a.level}</span></div><p class="mt-3 text-sm">${escapeText(a.message)}</p>${a.forecast_6h_mm!==undefined?`<p class="mt-3 text-xs">6-hour rainfall: ${a.forecast_6h_mm} mm · Maximum probability: ${a.max_probability_percent}%</p>`:''}${a.maximum_gust_6h_kmh!==undefined?`<p class="mt-3 text-xs">Maximum 6-hour gust: ${a.maximum_gust_6h_kmh} km/h</p>`:''}</article>`).join('');document.getElementById('weatherOfficialNotice').textContent=data.official_notice;document.getElementById('weatherUpdated').textContent=`Last updated: ${data.last_updated.replace('T',' ')} ${data.location.timezone} · Source: ${data.source}`;}catch(e){condition.textContent='Unavailable';document.getElementById('weatherOfficialNotice').textContent=e.message;}}
document.getElementById('refreshWeatherBtn')?.addEventListener('click',()=>loadWeatherModule(true));
async function overview(){try{const position=await browserLocation(),query=position?`?latitude=${position.latitude}&longitude=${position.longitude}`:'',alertRequest=manager?Api.get('/alerts/manage'):Api.get('/notifications/history');const [dashboard,allAlerts]=await Promise.all([Api.get(`/dashboard${query}`),alertRequest]),alerts=allAlerts.filter(a=>!a.status||a.status==='sent');const titles={admin:'Admin Dashboard',subadmin:'Municipal Dashboard',resident:'Resident Dashboard'};document.getElementById('dashboardTitle').textContent=titles[dashboard.role];document.getElementById('updatedAt').textContent=`Updated ${new Date(dashboard.generated_at).toLocaleString()}`;renderCards(dashboard.cards);renderCharts(dashboard.charts);document.getElementById('alertList').innerHTML=alerts.slice(0,5).map(alertMarkup).join('')||'<p class="text-sm text-slate-500">No active alerts.</p>';loadWeather(position||dashboard.municipality_center);}catch(e){toast(e.message);}}
let adminMap,marker,adminLayer,hazardDraftLayer,hazardDrawMode=null,hazardDrawPoints=[],hazardCursor=null;
let hazardMunicipalitiesLoaded=false;
function hazardAreaSquareMeters(ring){const radius=6378137;let area=0;for(let i=0;i<ring.length-1;i++){const [x1,y1]=ring[i],[x2,y2]=ring[i+1];area+=(x2-x1)*Math.PI/180*(2+Math.sin(y1*Math.PI/180)+Math.sin(y2*Math.PI/180));}return Math.abs(area*radius*radius/2);}
function setHazardDrawStatus(message,tone='info'){const status=document.getElementById('hazardDrawStatus');if(!status)return;status.textContent=message;status.dataset.tone=tone;}
function renderHazardDraft(){hazardDraftLayer?.remove();hazardDraftLayer=null;if(!adminMap||!hazardDrawMode||!hazardDrawPoints.length)return;if(hazardDrawMode==='rectangle'&&hazardCursor){hazardDraftLayer=L.rectangle(L.latLngBounds(hazardDrawPoints[0],hazardCursor),{color:'#2563eb',weight:3,dashArray:'7 6',fillOpacity:.16}).addTo(adminMap);}else{const points=hazardCursor?[...hazardDrawPoints,hazardCursor]:hazardDrawPoints;hazardDraftLayer=L.polyline(points,{color:'#2563eb',weight:3,dashArray:'7 6'}).addTo(adminMap);}}
function stopHazardDrawing(clear=false){hazardDrawMode=null;hazardDrawPoints=[];hazardCursor=null;hazardDraftLayer?.remove();hazardDraftLayer=null;document.getElementById('adminMap')?.classList.remove('hazard-drawing');document.querySelectorAll('[data-hazard-draw]').forEach(button=>button.classList.remove('is-active'));if(clear){marker?.remove();marker=null;const form=document.getElementById('hazardForm');if(form)form.elements.geojson_text.value='';document.getElementById('hazardCoverage')?.replaceChildren();setHazardDrawStatus('Choose Rectangle or Polygon to map a hazard area.');}}
function startHazardDrawing(mode){Modal.close('hazardFormCard');stopHazardDrawing(false);hazardDrawMode=mode;document.getElementById('adminMap')?.classList.add('hazard-drawing');document.querySelector(`[data-hazard-draw="${mode}"]`)?.classList.add('is-active');setHazardDrawStatus(mode==='rectangle'?'Click the first corner, then click the opposite corner.':'Click each boundary point, then select Finish area.','active');}
async function lookupHazardCoverage(geojson){const panel=document.getElementById('hazardCoverage');if(!panel)return;panel.className='hazard-coverage is-loading';panel.innerHTML='<strong>Checking covered locations…</strong><p>Comparing the area with verified GIS coordinates.</p>';try{const result=await Api.post('/gis/covered-locations',{geojson_data:geojson}),municipalities=result.municipalities||[],safeZones=result.safe_zones||[],centers=result.evacuation_centers||[],form=document.getElementById('hazardForm');if(user.role==='admin'&&municipalities.length)form.elements.municipality_id.value=municipalities[0].id;const names=municipalities.map(x=>x.municipality_name);panel.className='hazard-coverage';panel.innerHTML=`<div><span>Covered locations</span><strong>${names.length?names.map(escapeText).join(', '):'No municipality center detected'}</strong></div><div class="hazard-coverage-counts"><span><b>${municipalities.length}</b> municipalities</span><span><b>${safeZones.length}</b> safe zones</span><span><b>${centers.length}</b> evacuation centers</span></div>${safeZones.length||centers.length?`<p>${[...safeZones,...centers].map(x=>escapeText(x.name)).join(' · ')}</p>`:'<p>Only locations with verified coordinates can be detected.</p>'}`;}catch(error){panel.className='hazard-coverage has-error';panel.innerHTML=`<strong>Location lookup failed</strong><p>${escapeText(error.message)}</p>`;}}
function completeHazardDrawing(geojson){const form=document.getElementById('hazardForm');openHazardForm();form.elements.geojson_text.value=JSON.stringify(geojson,null,2);previewHazard(geojson);stopHazardDrawing(false);const ring=geojson.coordinates[0],hectares=hazardAreaSquareMeters(ring)/10000;setHazardDrawStatus(`Area captured · ${hectares.toFixed(2)} hectares`,'success');lookupHazardCoverage(geojson);}
function finishHazardPolygon(){if(hazardDrawMode!=='polygon')return;if(hazardDrawPoints.length<3){setHazardDrawStatus('Add at least three boundary points before finishing.','error');return;}const ring=hazardDrawPoints.map(p=>[Number(p.lng.toFixed(7)),Number(p.lat.toFixed(7))]);ring.push([...ring[0]]);completeHazardDrawing({type:'Polygon',coordinates:[ring]});}
function ensureHazardDrawingUi(){const map=document.getElementById('adminMap'),host=map?.parentElement;if(!host||document.getElementById('hazardDrawTools'))return;host.classList.add('hazard-map-host');host.insertAdjacentHTML('afterend','<aside id="hazardDrawTools" class="hazard-draw-tools"><div class="hazard-draw-heading"><div><strong>Map hazard coverage</strong><span>Select a shape, then draw the exact affected boundary on the map.</span></div></div><div class="hazard-shape-picker"><button type="button" data-hazard-draw="rectangle"><span>▭</span><div><strong>Rectangle</strong><small>Two opposite corners</small></div></button><button type="button" data-hazard-draw="polygon"><span>⬠</span><div><strong>Irregular polygon</strong><small>Three or more boundary points</small></div></button></div><div class="hazard-draw-actions"><button type="button" id="finishHazardArea">✓ Finish area</button><button type="button" id="undoHazardPoint">↶ Undo point</button><button type="button" id="clearHazardArea">Clear drawing</button></div><p id="hazardDrawStatus" data-tone="info">Choose Rectangle or Irregular polygon to begin.</p><div class="hazard-draw-help"><strong>How to draw</strong><ol><li>Select the shape.</li><li>Click boundary points on the map.</li><li>Finish the area and complete its details.</li></ol></div></aside>');document.querySelectorAll('[data-hazard-draw]').forEach(button=>button.addEventListener('click',()=>startHazardDrawing(button.dataset.hazardDraw)));document.getElementById('finishHazardArea').onclick=finishHazardPolygon;document.getElementById('undoHazardPoint').onclick=()=>{if(hazardDrawMode==='polygon'&&hazardDrawPoints.length){hazardDrawPoints.pop();renderHazardDraft();setHazardDrawStatus(`${hazardDrawPoints.length} boundary point${hazardDrawPoints.length===1?'':'s'} added.`,'active');}};document.getElementById('clearHazardArea').onclick=()=>stopHazardDrawing(true);const error=document.getElementById('hazardFormError'),coverage=document.createElement('section');coverage.id='hazardCoverage';coverage.className='hazard-coverage hidden';error.before(coverage);}
async function initAdminMap(){if(adminMap){adminMap.invalidateSize();return;}ensureHazardDrawingUi();adminMap=L.map('adminMap').setView(Config.MAP_CENTER,Config.MAP_ZOOM);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'&copy; OpenStreetMap contributors'}).addTo(adminMap);adminLayer=L.geoJSON().addTo(adminMap);adminMap.on('click',e=>{if(!hazardDrawMode)return;if(hazardDrawMode==='rectangle'){if(!hazardDrawPoints.length){hazardDrawPoints=[e.latlng];setHazardDrawStatus('First corner set. Click the opposite corner.','active');}else{const bounds=L.latLngBounds(hazardDrawPoints[0],e.latlng),west=bounds.getWest(),east=bounds.getEast(),south=bounds.getSouth(),north=bounds.getNorth();completeHazardDrawing({type:'Polygon',coordinates:[[[west,south],[east,south],[east,north],[west,north],[west,south]]]});}renderHazardDraft();return;}hazardDrawPoints.push(e.latlng);setHazardDrawStatus(`${hazardDrawPoints.length} boundary point${hazardDrawPoints.length===1?'':'s'} added. ${hazardDrawPoints.length>=3?'Select Finish area when ready.':''}`,'active');renderHazardDraft();});adminMap.on('mousemove',e=>{if(!hazardDrawMode||!hazardDrawPoints.length)return;hazardCursor=e.latlng;renderHazardDraft();});if(!hazardMunicipalitiesLoaded){const select=document.getElementById('hazardForm').elements.municipality_id;if(user.role==='subadmin'){select.add(new Option(user.municipality_name||'Assigned municipality',user.municipality_id));select.value=user.municipality_id;select.disabled=true;}else{const rows=await Api.get('/municipalities/options');rows.forEach(m=>select.add(new Option(m.municipality_name,m.id)));}hazardMunicipalitiesLoaded=true;}loadAdminHazards();}
function previewHazard(geojson){marker?.remove();marker=L.geoJSON(geojson,{style:{color:'#4f46e5',weight:3,fillOpacity:.25},pointToLayer:(f,ll)=>L.circleMarker(ll,{radius:9,color:'#4f46e5',fillOpacity:.8})}).addTo(adminMap);const bounds=marker.getBounds();if(bounds.isValid())adminMap.fitBounds(bounds.pad(.2),{maxZoom:15});}
async function loadAdminHazards(){try{const scope=user.role==='subadmin'?`?municipality_id=${user.municipality_id}`:'',hs=await Api.get(`/hazards${scope}`);adminLayer.clearLayers();hs.forEach(h=>L.geoJSON(h.geojson_data,{style:{color:colors[h.risk_level],weight:3,fillOpacity:.25},pointToLayer:(f,ll)=>L.circleMarker(ll,{radius:8,color:colors[h.risk_level],fillOpacity:.8})}).bindPopup(escapeText(h.hazard_name)).addTo(adminLayer));document.getElementById('hazardsTable').innerHTML=hs.map(h=>`<tr class="border-t"><td class="p-4 font-medium">${escapeText(h.hazard_name)}</td><td class="p-4">${escapeText(h.hazard_type.replaceAll('_',' '))}</td><td class="p-4">${escapeText(h.municipality_name||'—')}</td><td class="p-4"><span class="rounded-full px-2 py-1 text-xs severity-${h.risk_level} text-white">${h.risk_level}</span></td><td class="p-4 text-right"><button data-action="edit" data-id="${h.id}" class="mr-3 text-amber-600">Edit</button><button data-action="delete" data-id="${h.id}" class="text-red-600">Delete</button></td></tr>`).join('')||'<tr><td colspan="5" class="p-8 text-center text-slate-500">No hazards found.</td></tr>';}catch(e){toast(e.message);}}
function openHazardForm(item=null){const form=document.getElementById('hazardForm');document.getElementById('hazardFormCard').classList.remove('hidden');form.reset();form.elements.id.value=item?.id||'';form.elements.hazard_name.value=item?.hazard_name||'';form.elements.hazard_type.value=item?.hazard_type||'flood_zone';form.elements.municipality_id.value=user.role==='subadmin'?user.municipality_id:(item?.municipality_id||'');form.elements.risk_level.value=item?.risk_level||'low';form.elements.description.value=item?.description||'';form.elements.geojson_text.value=item?JSON.stringify(item.geojson_data,null,2):'';document.getElementById('hazardFormTitle').textContent=item?'Edit hazard':'Add hazard';document.getElementById('hazardFormError').classList.add('hidden');const coverage=document.getElementById('hazardCoverage');if(coverage){coverage.className='hazard-coverage hidden';coverage.replaceChildren();}if(item){previewHazard(item.geojson_data);lookupHazardCoverage(item.geojson_data);}else{marker?.remove();marker=null;}}
const newHazardButton=document.getElementById('newHazardBtn');if(newHazardButton){newHazardButton.textContent='Draw hazard area';newHazardButton.addEventListener('click',()=>{initAdminMap();startHazardDrawing('polygon');});}
document.getElementById('geojsonFile')?.addEventListener('change',async e=>{const error=document.getElementById('hazardFormError');try{const file=e.target.files[0];if(!file)return;if(file.size>2097152)throw new Error('GeoJSON file must not exceed 2 MB');const geojson=JSON.parse(await file.text());document.getElementById('hazardForm').elements.geojson_text.value=JSON.stringify(geojson,null,2);previewHazard(geojson);lookupHazardCoverage(geojson);error.classList.add('hidden');}catch(err){error.textContent=err.message||'Invalid GeoJSON file';error.classList.remove('hidden');}});
document.getElementById('hazardsTable')?.addEventListener('click',async e=>{const button=e.target.closest('button[data-action]');if(!button)return;try{const item=await Api.get(`/hazards/${button.dataset.id}`);if(button.dataset.action==='edit')openHazardForm(item);else if(await confirmAction(`Delete ${item.hazard_name}?`)){await Api.delete(`/hazards/${item.id}`);toast('Hazard deleted');marker?.remove();loadAdminHazards();overview();}}catch(err){toast(err.message);}});
document.getElementById('hazardForm')?.addEventListener('submit',async e=>{e.preventDefault();const error=document.getElementById('hazardFormError'),d=Object.fromEntries(new FormData(e.target)),id=d.id;delete d.id;try{d.geojson_data=JSON.parse(d.geojson_text);delete d.geojson_text;if(id)await Api.put(`/hazards/${id}`,d);else await Api.post('/hazards',d);e.target.reset();document.getElementById('hazardFormCard').classList.add('hidden');marker?.remove();marker=null;toast(id?'Hazard updated':'Hazard added');loadAdminHazards();overview();}catch(err){error.textContent=err.message;error.classList.remove('hidden');}});
const userPanel=document.getElementById('userPanel'),userForm=document.getElementById('userForm'),userDetails=document.getElementById('userDetails');let userMunicipalitiesLoaded=false;
async function ensureUserMunicipalities(){if(userMunicipalitiesLoaded||user.role!=='admin')return;const rows=await Api.get('/municipalities/options');rows.forEach(m=>userForm.elements.municipality_id.add(new Option(m.municipality_name,m.id)));userMunicipalitiesLoaded=true;}
async function openUserForm(item=null){await ensureUserMunicipalities();userPanel.classList.remove('hidden');userDetails.classList.add('hidden');userForm.classList.remove('hidden');userForm.reset();['id','fullname','email','phone','address','municipality_id','barangay','role'].forEach(k=>userForm.elements[k].value=item?.[k]??(k==='role'?'resident':''));userForm.elements.password.required=!item;document.getElementById('userPanelTitle').textContent=item?'Edit user':'Create user';document.getElementById('userFormError').classList.add('hidden');}
async function loadUsers(){try{const rows=await Api.get('/users');document.getElementById('usersScopeText').textContent=user.role==='subadmin'?'Residents assigned to your municipality.':'Manage all system accounts.';document.getElementById('usersTable').innerHTML=rows.map(u=>{const controls=user.role==='admin'?`<button data-action="edit" data-id="${u.id}" class="mr-2 text-amber-600">Edit</button>${u.status==='active'?`<button data-action="disable" data-id="${u.id}" class="mr-2 text-orange-600">Disable</button>`:u.status==='disabled'?`<button data-action="activate" data-id="${u.id}" class="mr-2 text-emerald-600">Activate</button>`:''}${u.status!=='deleted'?`<button data-action="delete" data-id="${u.id}" class="text-red-600">Delete</button>`:''}`:'';return `<tr class="border-t"><td class="p-4"><p class="font-medium">${escapeText(u.fullname)}</p><p class="text-xs text-slate-500">${escapeText(u.email)}</p></td><td class="p-4">${escapeText(u.role)}</td><td class="p-4">${escapeText(u.municipality_name||'—')}</td><td class="p-4"><span class="rounded-full px-2 py-1 text-xs ${u.status==='active'?'bg-emerald-50 text-emerald-700':u.status==='disabled'?'bg-orange-50 text-orange-700':'bg-slate-100 text-slate-600'}">${u.status}</span></td><td class="whitespace-nowrap p-4 text-right"><button data-action="view" data-id="${u.id}" class="mr-2 text-indigo-600">View</button>${controls}</td></tr>`;}).join('')||'<tr><td colspan="5" class="p-8 text-center text-slate-500">No users found.</td></tr>';}catch(e){toast(e.message);}}
document.getElementById('addUserBtn')?.addEventListener('click',()=>openUserForm());document.getElementById('closeUserPanel')?.addEventListener('click',()=>userPanel.classList.add('hidden'));
document.getElementById('usersTable')?.addEventListener('click',async e=>{const button=e.target.closest('button[data-action]');if(!button)return;try{const item=await Api.get(`/users/${button.dataset.id}`),action=button.dataset.action;if(action==='view'){userPanel.classList.remove('hidden');userForm.classList.add('hidden');userDetails.classList.remove('hidden');document.getElementById('userPanelTitle').textContent='User details';userDetails.innerHTML=`<p><b>Name:</b> ${escapeText(item.fullname)}</p><p><b>Email:</b> ${escapeText(item.email)}</p><p><b>Phone:</b> ${escapeText(item.phone||'—')}</p><p><b>Address:</b> ${escapeText(item.address||'—')}</p><p><b>Municipality:</b> ${escapeText(item.municipality_name||'—')}</p><p><b>Barangay:</b> ${escapeText(item.barangay||'—')}</p><p><b>Role:</b> ${escapeText(item.role)}</p><p><b>Status:</b> ${escapeText(item.status)}</p>`;}else if(action==='edit')await openUserForm(item);else if(action==='disable'&&await confirmAction(`Disable ${item.fullname}?`)){await Api.put(`/users/${item.id}/disable`,{});toast('User disabled');loadUsers();overview();}else if(action==='activate'&&await confirmAction(`Activate ${item.fullname}?`)){await Api.put(`/users/${item.id}/activate`,{});toast('User activated');loadUsers();overview();}else if(action==='delete'&&await confirmAction(`Delete ${item.fullname}? This account will no longer be usable.`)){await Api.delete(`/users/${item.id}`);toast('User deleted');loadUsers();overview();}}catch(err){toast(err.message);}});
userForm?.addEventListener('submit',async e=>{e.preventDefault();const error=document.getElementById('userFormError'),data=Object.fromEntries(new FormData(e.target)),id=data.id;delete data.id;error.classList.add('hidden');try{if(id)await Api.put(`/users/${id}`,data);else await Api.post('/users',data);userPanel.classList.add('hidden');toast(id?'User updated':'User created');loadUsers();overview();}catch(err){error.textContent=err.message;error.classList.remove('hidden');}});
