function openMunicipalityForm(item=null){municipalityPanel.classList.remove('hidden');municipalityDetails.classList.add('hidden');municipalityForm.classList.remove('hidden');municipalityForm.reset();municipalityForm.elements.id.value=item?.id||'';municipalityForm.elements.municipality_name.value=item?.municipality_name||'';municipalityForm.elements.description.value=item?.description||'';municipalityForm.elements.status.value=item?.status||'active';document.getElementById('municipalityPanelTitle').textContent=item?'Edit municipality':'Add municipality';document.getElementById('municipalityFormError').classList.add('hidden');}
async function loadMunicipalities(){try{const rows=await Api.get('/municipalities');document.getElementById('municipalitiesTable').innerHTML=rows.map(m=>`<tr class="border-t"><td class="p-4 font-medium">${escapeText(m.municipality_name)}</td><td class="max-w-xs truncate p-4 text-slate-500">${escapeText(m.description||'—')}</td><td class="p-4"><span class="rounded-full px-2 py-1 text-xs ${m.status==='active'?'bg-emerald-50 text-emerald-700':'bg-slate-100 text-slate-600'}">${m.status}</span></td><td class="p-4 text-right"><button data-action="view" data-id="${m.id}" class="mr-2 text-indigo-600">View</button><button data-action="edit" data-id="${m.id}" class="mr-2 text-amber-600">Edit</button><button data-action="delete" data-id="${m.id}" class="text-red-600">Delete</button></td></tr>`).join('')||'<tr><td colspan="4" class="p-8 text-center text-slate-500">No municipalities found.</td></tr>';}catch(e){toast(e.message);}}
