let safeZoneMap,safeZoneLayer,userLocationLayer,safeZoneMunicipalitiesLoaded=false;
async function initSafeZoneMap(){if(safeZoneMap){safeZoneMap.invalidateSize();loadSafeZones();return;}safeZoneMap=L.map('safeZoneMap').setView(Config.MAP_CENTER,Config.MAP_ZOOM);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'&copy; OpenStreetMap contributors'}).addTo(safeZoneMap);safeZoneLayer=L.layerGroup().addTo(safeZoneMap);if(manager)safeZoneMap.on('click',e=>{openSafeZoneForm();const form=document.getElementById('safeZoneForm');form.elements.latitude.value=e.latlng.lat.toFixed(7);form.elements.longitude.value=e.latlng.lng.toFixed(7);});if(manager&&!safeZoneMunicipalitiesLoaded){const select=document.getElementById('safeZoneForm').elements.municipality_id;if(user.role==='subadmin'){select.add(new Option(user.municipality_name||'Assigned municipality',user.municipality_id));select.value=user.municipality_id;select.disabled=true;}else{const rows=await Api.get('/municipalities/options');rows.forEach(m=>select.add(new Option(m.municipality_name,m.id)));}safeZoneMunicipalitiesLoaded=true;}loadSafeZones();}
function renderSafeZones(rows,nearest=false){safeZoneLayer.clearLayers();const bounds=[];rows.forEach(s=>{const latlng=[s.latitude,s.longitude],label=`<strong>${escapeText(s.safezone_name)}</strong><br>${escapeText(s.address)}<br>Capacity: ${s.capacity??'Not specified'}${s.distance_km!==undefined?`<br><b>${s.distance_km} km away</b>`:''}`;L.marker(latlng).bindPopup(label).addTo(safeZoneLayer);bounds.push(latlng);});if(bounds.length)safeZoneMap.fitBounds(bounds,{padding:[35,35],maxZoom:15});document.getElementById('safeZonesTable').innerHTML=rows.map(s=>`<tr class="border-t"><td class="p-4"><p class="font-medium">${escapeText(s.safezone_name)}</p>${s.distance_km!==undefined?`<p class="text-xs font-semibold text-emerald-600">${s.distance_km} km away</p>`:''}</td><td class="p-4">${escapeText(s.municipality_name)}</td><td class="p-4">${escapeText(s.address)}</td><td class="p-4">${s.capacity??'—'}</td><td class="p-4 text-right"><button data-action="view" data-id="${s.id}" class="mr-3 text-indigo-600">View</button>${manager?`<button data-action="edit" data-id="${s.id}" class="mr-3 text-amber-600">Edit</button><button data-action="delete" data-id="${s.id}" class="text-red-600">Delete</button>`:''}</td></tr>`).join('')||'<tr><td colspan="5" class="p-8 text-center text-slate-500">No safe zones found.</td></tr>';if(nearest&&rows[0])toast(`Nearest safe zone: ${rows[0].safezone_name} (${rows[0].distance_km} km)`);}
async function loadSafeZones(){try{renderSafeZones(await Api.get('/safe-zones'));}catch(e){toast(e.message);}}
function openSafeZoneForm(item=null){const card=document.getElementById('safeZoneFormCard'),form=document.getElementById('safeZoneForm');if(!card||!form)return;card.classList.remove('hidden');form.reset();['id','safezone_name','municipality_id','address','latitude','longitude','capacity','description'].forEach(k=>form.elements[k].value=item?.[k]??'');if(user.role==='subadmin'){form.elements.municipality_id.value=user.municipality_id;form.elements.municipality_id.disabled=true;}document.getElementById('safeZoneFormTitle').textContent=item?'Edit safe zone':'Add safe zone';document.getElementById('safeZoneFormError').classList.add('hidden');}
document.getElementById('newSafeZoneBtn')?.addEventListener('click',()=>openSafeZoneForm());
document.getElementById('nearestSafeZoneBtn')?.addEventListener('click',()=>{if(!navigator.geolocation){toast('Geolocation is not supported');return;}navigator.geolocation.getCurrentPosition(async p=>{try{const lat=p.coords.latitude,lng=p.coords.longitude,rows=await Api.get(`/safe-zones/nearest?latitude=${lat}&longitude=${lng}&limit=5`);userLocationLayer?.remove();userLocationLayer=L.circleMarker([lat,lng],{radius:9,color:'#2563eb',fillColor:'#60a5fa',fillOpacity:1}).bindPopup('Your location').addTo(safeZoneMap);renderSafeZones(rows,true);userLocationLayer.addTo(safeZoneMap);}catch(e){toast(e.message);}},()=>toast('Location permission is required to find the nearest safe zone'),{enableHighAccuracy:true,timeout:8000});});
document.getElementById('safeZonesTable')?.addEventListener('click',async e=>{const button=e.target.closest('button[data-action]');if(!button)return;try{const item=await Api.get(`/safe-zones/${button.dataset.id}`);if(button.dataset.action==='view'){L.popup().setLatLng([item.latitude,item.longitude]).setContent(`<strong>${escapeText(item.safezone_name)}</strong><br>${escapeText(item.description||item.address)}<br>Capacity: ${item.capacity??'Not specified'}`).openOn(safeZoneMap);safeZoneMap.setView([item.latitude,item.longitude],15);}else if(button.dataset.action==='edit')openSafeZoneForm(item);else if(await confirmAction(`Delete ${item.safezone_name}?`)){await Api.delete(`/safe-zones/${item.id}`);toast('Safe zone deleted');loadSafeZones();overview();}}catch(err){toast(err.message);}});
document.getElementById('safeZoneForm')?.addEventListener('submit',async e=>{e.preventDefault();const error=document.getElementById('safeZoneFormError'),data=Object.fromEntries(new FormData(e.target)),id=data.id;delete data.id;if(user.role==='subadmin')data.municipality_id=user.municipality_id;error.classList.add('hidden');try{if(id)await Api.put(`/safe-zones/${id}`,data);else await Api.post('/safe-zones',data);document.getElementById('safeZoneFormCard').classList.add('hidden');toast(id?'Safe zone updated':'Safe zone added');loadSafeZones();overview();}catch(err){error.textContent=err.message;error.classList.remove('hidden');}});
let centerMap,centerLayer,centerUserLocationLayer,centerMunicipalitiesLoaded=false;
const centerStatusSelect=document.getElementById('centerForm')?.elements.status;if(centerStatusSelect)centerStatusSelect.innerHTML='<option value="available">Available</option><option value="full">Full</option><option value="closed">Closed</option><option value="under_maintenance">Under Maintenance</option>';
async function initCenterMap(){if(centerMap){centerMap.invalidateSize();loadCenters();return;}centerMap=L.map('centerMap').setView(Config.MAP_CENTER,Config.MAP_ZOOM);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'&copy; OpenStreetMap contributors'}).addTo(centerMap);centerLayer=L.layerGroup().addTo(centerMap);if(manager)centerMap.on('click',e=>{openCenterForm();const form=document.getElementById('centerForm');form.elements.latitude.value=e.latlng.lat.toFixed(7);form.elements.longitude.value=e.latlng.lng.toFixed(7);});if(manager&&!centerMunicipalitiesLoaded){const select=document.getElementById('centerForm').elements.municipality_id;if(user.role==='subadmin'){select.add(new Option(user.municipality_name||'Assigned municipality',user.municipality_id));select.value=user.municipality_id;select.disabled=true;}else{const rows=await Api.get('/municipalities/options');rows.forEach(m=>select.add(new Option(m.municipality_name,m.id)));}centerMunicipalitiesLoaded=true;}loadCenters();}
function renderCenters(rows,nearest=false){centerLayer.clearLayers();const bounds=[];rows.forEach(c=>{const latlng=[c.latitude,c.longitude],color=c.status==='open'?'#16a34a':c.status==='standby'?'#7c3aed':'#64748b';L.circleMarker(latlng,{radius:9,color,fillColor:color,fillOpacity:.85}).bindPopup(`<strong>${escapeText(c.center_name)}</strong><br>${escapeText(c.address)}<br>Status: ${escapeText(c.status)}<br>Capacity: ${c.capacity}${c.contact_number?`<br>Contact: ${escapeText(c.contact_number)}`:''}${c.distance_km!==undefined?`<br><b>${c.distance_km} km away</b>`:''}`).addTo(centerLayer);bounds.push(latlng);});if(bounds.length)centerMap.fitBounds(bounds,{padding:[35,35],maxZoom:15});document.getElementById('centersTable').innerHTML=rows.map(c=>`<tr class="border-t"><td class="p-4"><p class="font-medium">${escapeText(c.center_name)}</p><p class="text-xs text-slate-500">${escapeText(c.address)}</p>${c.distance_km!==undefined?`<p class="text-xs font-semibold text-violet-600">${c.distance_km} km away</p>`:''}</td><td class="p-4">${escapeText(c.municipality_name)}</td><td class="p-4"><span class="rounded-full px-2 py-1 text-xs ${c.status==='open'?'bg-emerald-50 text-emerald-700':c.status==='standby'?'bg-violet-50 text-violet-700':'bg-slate-100 text-slate-600'}">${c.status}</span></td><td class="p-4">${c.capacity}</td><td class="p-4">${escapeText(c.contact_number||'—')}</td><td class="p-4 text-right"><button data-action="view" data-id="${c.id}" class="mr-3 text-indigo-600">View</button>${manager?`<button data-action="edit" data-id="${c.id}" class="mr-3 text-amber-600">Edit</button><button data-action="delete" data-id="${c.id}" class="text-red-600">Delete</button>`:''}</td></tr>`).join('')||'<tr><td colspan="6" class="p-8 text-center text-slate-500">No evacuation centers found.</td></tr>';if(nearest&&rows[0])toast(`Nearest center: ${rows[0].center_name} (${rows[0].distance_km} km)`);}
async function loadCenters(){try{renderCenters(await Api.get('/evacuation-centers'));}catch(e){toast(e.message);}}
function openCenterForm(item=null){const card=document.getElementById('centerFormCard'),form=document.getElementById('centerForm');if(!card||!form)return;card.classList.remove('hidden');form.reset();['id','center_name','municipality_id','address','contact_number','capacity','status','latitude','longitude'].forEach(k=>form.elements[k].value=item?.[k]??(k==='status'?'available':''));if(user.role==='subadmin'){form.elements.municipality_id.value=user.municipality_id;form.elements.municipality_id.disabled=true;}document.getElementById('centerFormTitle').textContent=item?'Edit evacuation center':'Add evacuation center';document.getElementById('centerFormError').classList.add('hidden');}
document.getElementById('newCenterBtn')?.addEventListener('click',()=>openCenterForm());
document.getElementById('nearestCenterBtn')?.addEventListener('click',()=>{if(!navigator.geolocation){toast('Geolocation is not supported');return;}navigator.geolocation.getCurrentPosition(async p=>{try{const lat=p.coords.latitude,lng=p.coords.longitude,rows=await Api.get(`/evacuation-centers/nearest?latitude=${lat}&longitude=${lng}&limit=5`);centerUserLocationLayer?.remove();centerUserLocationLayer=L.circleMarker([lat,lng],{radius:9,color:'#2563eb',fillColor:'#60a5fa',fillOpacity:1}).bindPopup('Your location').addTo(centerMap);renderCenters(rows,true);centerUserLocationLayer.addTo(centerMap);}catch(e){toast(e.message);}},()=>toast('Location permission is required to find the nearest center'),{enableHighAccuracy:true,timeout:8000});});
document.getElementById('centersTable')?.addEventListener('click',async e=>{const button=e.target.closest('button[data-action]');if(!button)return;try{const item=await Api.get(`/evacuation-centers/${button.dataset.id}`);if(button.dataset.action==='view'){L.popup().setLatLng([item.latitude,item.longitude]).setContent(`<strong>${escapeText(item.center_name)}</strong><br>${escapeText(item.address)}<br>Status: ${escapeText(item.status)}<br>Capacity: ${item.capacity}<br>Contact: ${escapeText(item.contact_number||'Not provided')}`).openOn(centerMap);centerMap.setView([item.latitude,item.longitude],15);}else if(button.dataset.action==='edit')openCenterForm(item);else if(await confirmAction(`Delete ${item.center_name}?`)){await Api.delete(`/evacuation-centers/${item.id}`);toast('Evacuation center deleted');loadCenters();overview();}}catch(err){toast(err.message);}});
document.getElementById('centerForm')?.addEventListener('submit',async e=>{e.preventDefault();const error=document.getElementById('centerFormError'),data=Object.fromEntries(new FormData(e.target)),id=data.id;delete data.id;if(user.role==='subadmin')data.municipality_id=user.municipality_id;error.classList.add('hidden');try{if(id)await Api.put(`/evacuation-centers/${id}`,data);else await Api.post('/evacuation-centers',data);document.getElementById('centerFormCard').classList.add('hidden');toast(id?'Center updated':'Center added');loadCenters();overview();}catch(err){error.textContent=err.message;error.classList.remove('hidden');}});
let routeMap,routeLayer,savedRoutesLayer,currentPlan,routeEditingId=null;
async function initRouteMap(){if(routeMap){routeMap.invalidateSize();return;}routeMap=L.map('routeMap').setView(Config.MAP_CENTER,Config.MAP_ZOOM);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'&copy; OpenStreetMap contributors'}).addTo(routeMap);savedRoutesLayer=L.geoJSON(null,{style:{color:'#64748b',weight:3,opacity:.55}}).addTo(routeMap);routeLayer=L.layerGroup().addTo(routeMap);loadSavedRoutes(false);}
function currentPosition(){return new Promise((resolve,reject)=>navigator.geolocation?navigator.geolocation.getCurrentPosition(p=>resolve({latitude:p.coords.latitude,longitude:p.coords.longitude}),()=>reject(new Error('Location permission is required to plan a route')),{enableHighAccuracy:true,timeout:10000,maximumAge:60000}):reject(new Error('Geolocation is not supported')));}
async function planNearestRoute(type){try{document.getElementById('routeSummary').innerHTML='<p>Calculating nearest destination and road route…</p>';const start=await currentPosition(),nearest=await Api.get(`/evacuation-routes/nearest-destination?type=${type}&latitude=${start.latitude}&longitude=${start.longitude}`),destination=nearest.destination,end={latitude:destination.latitude,longitude:destination.longitude},road=await Api.get(`/evacuation-routes/road?start_lat=${start.latitude}&start_lng=${start.longitude}&end_lat=${end.latitude}&end_lng=${end.longitude}`),destinationName=type==='safe_zone'?destination.safezone_name:destination.center_name;currentPlan={start_location:{name:'Current location',...start},end_location:{name:destinationName,...end},geojson_data:road.geojson_data};routeLayer.clearLayers();const line=L.geoJSON(road.geojson_data,{style:{color:'#dc2626',weight:6,opacity:.85}}).addTo(routeLayer),startMarker=L.circleMarker([start.latitude,start.longitude],{radius:8,color:'#2563eb',fillOpacity:1}).bindPopup('Your location').addTo(routeLayer),endMarker=L.marker([end.latitude,end.longitude]).bindPopup(escapeText(destinationName)).addTo(routeLayer);routeMap.fitBounds(line.getBounds().extend(startMarker.getLatLng()).extend(endMarker.getLatLng()),{padding:[40,40]});const distance=(road.distance_m/1000).toFixed(1),duration=road.duration_s?`${Math.ceil(road.duration_s/60)} min`:'Unavailable';document.getElementById('routeSummary').innerHTML=`<h2 class="font-semibold text-slate-900">${escapeText(destinationName)}</h2><p class="mt-2"><b>Distance:</b> ${distance} km</p><p><b>Estimated drive:</b> ${duration}</p><p><b>Routing:</b> ${road.source==='osrm'?'Road network':'Straight-line fallback'}</p><p class="mt-2 text-xs">Always follow official evacuation instructions and current road closures.</p>`;document.getElementById('saveRouteForm')?.classList.remove('hidden');}catch(e){document.getElementById('routeSummary').innerHTML=`<p class="text-red-600">${escapeText(e.message)}</p>`;}}
async function loadSavedRoutes(draw=true){try{const rows=await Api.get('/evacuation-routes');document.getElementById('routesTable').innerHTML=rows.map(r=>`<tr class="border-t"><td class="p-4 font-medium">${escapeText(r.route_name)}</td><td class="p-4">${escapeText(r.start_location.name)}</td><td class="p-4">${escapeText(r.end_location.name)}</td><td class="p-4 text-right"><button data-action="view" data-id="${r.id}" class="mr-3 text-indigo-600">Visualize</button>${manager?`<button data-action="edit" data-id="${r.id}" class="mr-3 text-amber-600">Edit</button><button data-action="delete" data-id="${r.id}" class="text-red-600">Delete</button>`:''}</td></tr>`).join('')||'<tr><td colspan="4" class="p-8 text-center text-slate-500">No saved routes.</td></tr>';if(draw){savedRoutesLayer.clearLayers();rows.forEach(r=>savedRoutesLayer.addData(r.geojson_data));const bounds=savedRoutesLayer.getBounds();if(bounds.isValid())routeMap.fitBounds(bounds,{padding:[35,35]});}}catch(e){showError(e.message);}}
document.getElementById('routeToSafeZoneBtn')?.addEventListener('click',()=>planNearestRoute('safe_zone'));document.getElementById('routeToCenterBtn')?.addEventListener('click',()=>planNearestRoute('evacuation_center'));document.getElementById('showSavedRoutesBtn')?.addEventListener('click',()=>loadSavedRoutes(true));
document.getElementById('saveRouteForm')?.addEventListener('submit',async e=>{e.preventDefault();const error=document.getElementById('routeFormError');if(!currentPlan){showError('Plan or select a route before saving.');return;}try{const payload={route_name:e.target.route_name.value,...currentPlan};if(routeEditingId)await Api.put(`/evacuation-routes/${routeEditingId}`,payload);else await Api.post('/evacuation-routes',payload);const updated=!!routeEditingId;routeEditingId=null;e.target.reset();e.target.classList.add('hidden');toast(updated?'Route updated':'Route saved');loadSavedRoutes(false);}catch(err){error.textContent=err.message;error.classList.remove('hidden');}});
document.getElementById('routesTable')?.addEventListener('click',async e=>{const button=e.target.closest('button[data-action]');if(!button)return;try{const item=await Api.get(`/evacuation-routes/${button.dataset.id}`),action=button.dataset.action;if(action==='view'){routeLayer.clearLayers();const line=L.geoJSON(item.geojson_data,{style:{color:'#dc2626',weight:6}}).bindPopup(escapeText(item.route_name)).addTo(routeLayer);L.marker([item.start_location.latitude,item.start_location.longitude]).bindPopup(escapeText(item.start_location.name)).addTo(routeLayer);L.marker([item.end_location.latitude,item.end_location.longitude]).bindPopup(escapeText(item.end_location.name)).addTo(routeLayer);routeMap.fitBounds(line.getBounds(),{padding:[40,40]});document.getElementById('routeSummary').innerHTML=`<h2 class="font-semibold text-slate-900">${escapeText(item.route_name)}</h2><p class="mt-2">${escapeText(item.start_location.name)} → ${escapeText(item.end_location.name)}</p>`;}else if(action==='edit'){routeEditingId=item.id;currentPlan={start_location:item.start_location,end_location:item.end_location,geojson_data:item.geojson_data,distance_km:item.distance_km,estimated_travel_minutes:item.estimated_travel_minutes};const form=document.getElementById('saveRouteForm');form.route_name.value=item.route_name;form.classList.remove('hidden');}else if(await confirmAction(`Delete ${item.route_name}?`)){await Api.delete(`/evacuation-routes/${item.id}`);toast('Route deleted');loadSavedRoutes(true);}}catch(err){showError(err.message);}});
let alertRows=[],alertMunicipalitiesLoaded=false;
async function ensureAlertMunicipalities(){if(!manager||alertMunicipalitiesLoaded)return;const form=document.getElementById('alertForm'),select=form.elements.municipality_id;if(user.role==='subadmin'){select.add(new Option(user.municipality_name||'Assigned municipality',user.municipality_id));select.value=user.municipality_id;select.disabled=true;}else{const rows=await Api.get('/municipalities/options');rows.forEach(m=>select.add(new Option(m.municipality_name,m.id)));}alertMunicipalitiesLoaded=true;}
async function openAlertForm(item=null){await ensureAlertMunicipalities();const card=document.getElementById('alertFormCard'),form=document.getElementById('alertForm');if(!card||!form)return;card.classList.remove('hidden');form.reset();['id','title','alert_type','alert_level','municipality_id','message'].forEach(k=>form.elements[k].value=item?.[k]??(k==='alert_type'?'emergency_alert':k==='alert_level'?'warning':''));if(user.role==='subadmin'){form.elements.municipality_id.value=user.municipality_id;form.elements.municipality_id.disabled=true;}document.getElementById('alertFormTitle').textContent=item?'Edit alert':'Create alert';document.getElementById('alertFormError').classList.add('hidden');}
async function loadAlertCenter(){try{alertRows=await Api.get(manager?'/alerts/manage':'/notifications/history');document.getElementById('alertsTable').innerHTML=alertRows.map(a=>{const status=manager?a.status:(a.is_read?'read':'unread'),actions=manager?`<button data-action="edit" data-id="${a.id}" class="mr-2 text-amber-600">Edit</button>${a.status!=='sent'?`<button data-action="send" data-id="${a.id}" class="mr-2 text-emerald-600">Send</button>`:''}<button data-action="delete" data-id="${a.id}" class="text-red-600">Delete</button>`:!a.is_read?`<button data-action="read" data-id="${a.id}" class="text-indigo-600">Mark read</button>`:'';return `<tr class="border-t ${!manager&&!a.is_read?'bg-indigo-50/50':''}"><td class="max-w-sm p-4"><p class="font-medium">${escapeText(a.title)}</p><p class="line-clamp-2 text-xs text-slate-500">${escapeText(a.message)}</p><p class="mt-1 text-xs text-slate-400">${new Date(a.sent_at||a.created_at).toLocaleString()}</p></td><td class="p-4">${escapeText(a.alert_type.replaceAll('_',' '))}</td><td class="p-4"><span class="rounded-full px-2 py-1 text-xs ${a.alert_level==='critical'?'bg-red-100 text-red-700':a.alert_level==='warning'?'bg-amber-100 text-amber-700':'bg-sky-100 text-sky-700'}">${a.alert_level}</span></td><td class="p-4">${escapeText(a.municipality_name||'Province-wide')}</td><td class="p-4">${status}</td><td class="whitespace-nowrap p-4 text-right">${actions}</td></tr>`;}).join('')||'<tr><td colspan="6" class="p-8 text-center text-slate-500">No alerts found.</td></tr>';if(!manager)updateUnreadBadge();}catch(e){toast(e.message);}}
document.getElementById('newAlertBtn')?.addEventListener('click',()=>openAlertForm());
document.getElementById('alertForm')?.addEventListener('submit',async e=>{e.preventDefault();const error=document.getElementById('alertFormError'),data=Object.fromEntries(new FormData(e.target)),id=data.id;delete data.id;if(user.role==='subadmin')data.municipality_id=user.municipality_id;error.classList.add('hidden');try{if(id)await Api.put(`/alerts/${id}`,data);else await Api.post('/alerts',data);document.getElementById('alertFormCard').classList.add('hidden');toast(id?'Alert updated':'Alert draft created');loadAlertCenter();overview();}catch(err){error.textContent=err.message;error.classList.remove('hidden');}});
document.getElementById('alertsTable')?.addEventListener('click',async e=>{const button=e.target.closest('button[data-action]');if(!button)return;try{const item=alertRows.find(a=>String(a.id)===button.dataset.id),action=button.dataset.action;if(action==='edit')openAlertForm(await Api.get(`/alerts/${item.id}`));else if(action==='send'&&await confirmAction(`Send ${item.title} now?`)){await Api.post(`/alerts/${item.id}/send`,{});toast('Alert sent');loadAlertCenter();overview();}else if(action==='delete'&&await confirmAction(`Delete ${item.title}?`)){await Api.delete(`/alerts/${item.id}`);toast('Alert deleted');loadAlertCenter();overview();}else if(action==='read'){await Api.post(`/notifications/${item.id}/read`,{});loadAlertCenter();overview();}}catch(err){toast(err.message);}});
document.getElementById('enableNotificationsBtn')?.addEventListener('click',async()=>{if(!('Notification'in window)){toast('Browser notifications are not supported');return;}const permission=await Notification.requestPermission();toast(permission==='granted'?'Browser notifications enabled':'Notification permission was not granted');});
async function updateUnreadBadge(){if(manager)return;try{const result=await Api.get('/notifications/unread-count'),badge=document.getElementById('alertBadge');badge.textContent=result.count;badge.classList.toggle('hidden',result.count===0);}catch{}}
async function pollResidentNotifications(){if(manager)return;try{const rows=await Api.get('/notifications/history'),unread=rows.filter(a=>!a.is_read),last=Number(sessionStorage.getItem('dm_last_notified_alert')||0),latest=unread.find(a=>Number(a.id)>last);if(latest){sessionStorage.setItem('dm_last_notified_alert',latest.id);toast(`${latest.title}: ${latest.message}`);if('Notification'in window&&Notification.permission==='granted')new Notification(latest.title,{body:latest.message,tag:`alert-${latest.id}`});}updateUnreadBadge();}catch{}}
pollResidentNotifications();setInterval(pollResidentNotifications,Config.ALERT_POLL_MS);
const reportLabels={hazard:'Hazard Report',alert:'Alert Report',historical_disaster:'Historical Disaster Report',evacuation_center:'Evacuation Center Report'};
const reportTypeSelect=document.getElementById('reportForm')?.elements.report_type;if(reportTypeSelect&&!reportTypeSelect.querySelector('[value="evacuation_center"]'))reportTypeSelect.add(new Option('Evacuation Center Report','evacuation_center'));
let historicalRows=[],historicalMunicipalitiesLoaded=false;
async function ensureHistoricalMunicipalities(){if(user.role!=='admin'||historicalMunicipalitiesLoaded)return;const select=document.getElementById('historicalForm').elements.municipality_id,rows=await Api.get('/municipalities/options');rows.forEach(m=>select.add(new Option(m.municipality_name,m.id)));historicalMunicipalitiesLoaded=true;}
function renderHistoricalDisasters(rows){const money=new Intl.NumberFormat(undefined,{minimumFractionDigits:2,maximumFractionDigits:2});document.getElementById('historicalTable').innerHTML=rows.map(r=>`<tr class="border-t"><td class="max-w-sm p-4"><p class="font-medium">${escapeText(r.title)}</p><p class="text-xs capitalize text-slate-500">${escapeText(r.disaster_type)}</p><p class="line-clamp-2 text-xs text-slate-400">${escapeText(r.description||'No description')}</p></td><td class="p-4">${escapeText(r.municipality_name)}</td><td class="whitespace-nowrap p-4">${escapeText(r.date_occurred)}</td><td class="p-4">${r.casualties}</td><td class="p-4">${money.format(r.damages)}</td><td class="whitespace-nowrap p-4 text-right"><button data-action="view" data-id="${r.id}" class="mr-3 text-indigo-600">View</button>${user.role==='admin'?`<button data-action="edit" data-id="${r.id}" class="mr-3 text-amber-600">Edit</button><button data-action="delete" data-id="${r.id}" class="text-red-600">Delete</button>`:''}</td></tr>`).join('')||'<tr><td colspan="6" class="p-8 text-center text-slate-500">No historical disaster records found.</td></tr>';}
async function loadHistoricalDisasters(){try{const form=document.getElementById('historicalFilters'),params=new URLSearchParams();if(form)for(const [key,value]of new FormData(form))if(value)params.set(key,value);historicalRows=await Api.get(`/historical-disasters${params.size?'?'+params:''}`);renderHistoricalDisasters(historicalRows);}catch(e){toast(e.message);}}
async function openHistoricalForm(item=null){await ensureHistoricalMunicipalities();const card=document.getElementById('historicalFormCard'),form=document.getElementById('historicalForm');card.classList.remove('hidden');form.reset();for(const key of ['id','title','disaster_type','municipality_id','date_occurred','casualties','damages','description'])form.elements[key].value=item?.[key]??(key==='casualties'||key==='damages'?0:'');form.elements.date_occurred.max=new Date().toISOString().slice(0,10);document.getElementById('historicalFormTitle').textContent=item?'Edit historical record':'Add historical record';document.getElementById('historicalFormError').classList.add('hidden');}
document.getElementById('newHistoricalBtn')?.addEventListener('click',()=>openHistoricalForm());
document.getElementById('historicalFilters')?.addEventListener('submit',e=>{e.preventDefault();loadHistoricalDisasters();});
document.getElementById('historicalForm')?.addEventListener('submit',async e=>{e.preventDefault();const data=Object.fromEntries(new FormData(e.target)),id=data.id,error=document.getElementById('historicalFormError');delete data.id;error.classList.add('hidden');try{if(id)await Api.put(`/historical-disasters/${id}`,data);else await Api.post('/historical-disasters',data);document.getElementById('historicalFormCard').classList.add('hidden');toast(id?'Historical record updated':'Historical record added');loadHistoricalDisasters();}catch(err){error.textContent=err.message;error.classList.remove('hidden');}});
document.getElementById('historicalTable')?.addEventListener('click',async e=>{const button=e.target.closest('button[data-action]');if(!button)return;try{const item=await Api.get(`/historical-disasters/${button.dataset.id}`);if(button.dataset.action==='view')Swal.fire({title:item.title,text:`${item.disaster_type} · ${item.date_occurred}\n${item.municipality_name}\nCasualties: ${item.casualties}\nDamages: ${Number(item.damages).toLocaleString(undefined,{minimumFractionDigits:2})}\n\n${item.description||'No description'}`,icon:'info'});else if(button.dataset.action==='edit')openHistoricalForm(item);else if(await confirmAction(`Delete ${item.title}? This cannot be undone.`)){await Api.delete(`/historical-disasters/${item.id}`);toast('Historical record deleted');loadHistoricalDisasters();}}catch(err){showError(err.message);}});
async function loadReports(){try{const rows=await Api.get('/reports');document.getElementById('reportsTable').innerHTML=rows.map(r=>`<tr class="border-t"><td class="p-4 font-medium">${reportLabels[r.report_type]||escapeText(r.report_type)}</td><td class="p-4 uppercase">${escapeText(r.format)}</td><td class="p-4">${escapeText(r.generated_by_name)}</td><td class="p-4">${new Date(r.generated_at.replace(' ','T')+'Z').toLocaleString()}</td><td class="p-4 text-right"><button data-id="${r.id}" data-filename="${escapeText(r.file_path.split('/').pop())}" class="text-indigo-600">Download</button></td></tr>`).join('')||'<tr><td colspan="5" class="p-8 text-center text-slate-500">No generated reports.</td></tr>';}catch(e){toast(e.message);}}
document.getElementById('reportForm')?.addEventListener('submit',async e=>{e.preventDefault();const error=document.getElementById('reportFormError'),button=e.target.querySelector('button[type="submit"]');error.classList.add('hidden');button.disabled=true;button.textContent='Generating…';try{await Api.post('/reports',Object.fromEntries(new FormData(e.target)));Modal.close(e.target);e.target.reset();toast('Report generated successfully');loadReports();}catch(err){error.textContent=err.message;error.classList.remove('hidden');}finally{button.disabled=false;button.textContent='Generate report';}});
document.getElementById('reportsTable')?.addEventListener('click',async e=>{const button=e.target.closest('button[data-id]');if(!button)return;button.disabled=true;try{const response=await fetch(`${Config.API_URL}/reports/${button.dataset.id}/download`,{headers:{Authorization:`Bearer ${Api.token()}`}});if(!response.ok){const payload=await response.json();throw new Error(payload.message||'Download failed');}const blob=await response.blob(),url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download=button.dataset.filename||'report';document.body.appendChild(link);link.click();link.remove();URL.revokeObjectURL(url);toast('Report download started');}catch(err){showError(err.message);}finally{button.disabled=false;}});
overview();


